import { isDefaultTooltipHandler } from '../hooks/use-tooltip-template.js';
import { BubbleLayerTooltip } from '../slots/BubbleLayerTooltip.js';
import { ChoroplethLayerTooltip } from '../slots/ChoroplethLayerTooltip.js';
import { ConnectionLayerTooltip } from '../slots/ConnectionLayerTooltip.js';
import { DotLayerTooltip } from '../slots/DotLayerTooltip.js';
import type {
  BubbleLayerTooltipHandler,
  ChoroplethLayerTooltipData,
  ChoroplethLayerTooltipHandler,
  ConnectionLayerTooltipData,
  ConnectionLayerTooltipHandler,
  DotLayerTooltipHandler,
  LayerTooltipData,
  LayerTooltipHandler,
} from '../types/tooltip.js';

/**
 * Type guards for tooltip template
 * @param template -
 */
export const isDotTooltipTemplate = (
  template?: LayerTooltipHandler | null,
): template is DotLayerTooltipHandler =>
  typeof template === typeof DotLayerTooltip;

export const isBubbleTooltipTemplate = (
  template?: LayerTooltipHandler | null,
): template is BubbleLayerTooltipHandler =>
  typeof template === typeof BubbleLayerTooltip;

export const isConnectionTooltipTemplate = (
  template?: LayerTooltipHandler | null,
): template is ConnectionLayerTooltipHandler =>
  typeof template === typeof ConnectionLayerTooltip;

export const isChoroplethTooltipTemplate = (
  template?: LayerTooltipHandler | null,
): template is ChoroplethLayerTooltipHandler =>
  typeof template === typeof ChoroplethLayerTooltip;

/**
 * Type guards for map types in tooltip context
 * @param data -
 */
export const isConnection = (
  data: LayerTooltipData,
): data is ConnectionLayerTooltipData => 'path' in data.data;

export const isRegion = (
  data: LayerTooltipData,
): data is ChoroplethLayerTooltipData => 'name' in data;

export { isDefaultTooltipHandler };
